arguments.cmd:
(cat /tmp/relevant_files.txt | xargs -r rg -i -o --no-filename -f /app/term_banks/drugs.txt || true) \
  | awk '{print tolower($0)}' \
  | sed 's/[[:space:]]\+/ /g' \
  | sort -u > /tmp/drugs_found.txt;

(cat /tmp/relevant_files.txt | xargs -r rg -i -o --no-filename -f /app/term_banks/phenotypes.txt || true) \
  | awk '{print tolower($0)}' \
  | sed 's/[[:space:]]\+/ /g' \
  | sort -u > /tmp/phenos_found.txt;

echo "Drugs matched:" $(wc -l < /tmp/drugs_found.txt);
echo "Phenotypes matched:" $(wc -l < /tmp/phenos_found.txt);
head -n 20 /tmp/drugs_found.txt; echo '...'; head -n 20 /tmp/phenos_found.txt;

