arguments.cmd:
node - << 'NODE'
const fs = require('fs');
function readList(path){
  if(!fs.existsSync(path)) return [];
  return fs.readFileSync(path,'utf8').split(/\r?\n/).map(s=>s.trim()).filter(Boolean);
}
const drugs = readList('/tmp/drugs_found.txt');
const phenos = readList('/tmp/phenos_found.txt');
const relfiles = readList('/tmp/relevant_files.txt');
const out = {drugs, phenotypes: phenos, relevant_paper_count: relfiles.length};
fs.writeFileSync('/app/answers.json', JSON.stringify(out, null, 2));
console.log('Wrote /app/answers.json with', drugs.length, 'drugs,', phenos.length, 'phenotypes, count =', relfiles.length);
